// Keep React keys and dictionary rows stable even when source batches overlap.
// Duplicate IDs previously caused cards from the prior category to remain visible.
function dedupeTags(items: PromptTag[]): PromptTag[] {
  const usedIds = new Set<string>()
  const usedEntries = new Set<string>()
  const result: PromptTag[] = []

  for (const item of items) {
    const entryKey = `${item.category}::${item.prompt.trim().toLowerCase()}`
    if (usedEntries.has(entryKey)) continue

    let id = item.id
    let suffix = 2
    while (usedIds.has(id)) id = `${item.id}-${suffix++}`

    usedIds.add(id)
    usedEntries.add(entryKey)
    result.push(id === item.id ? item : { ...item, id })
  }
  return result
}

export const tags: PromptTag[] = dedupeTags(rawTags)
export const TAG_COUNT = tags.length
